<?php namespace App\Services; use Illuminate\Support\Facades\Storage; use Illuminate\Support\Facades\Process; use Illuminate\Support\Facades\Log; use Exception; use ZipArchive; class BackupService { public function backupDatabase(string $filename = 'db_backup.sql.gz'): string { $path = storage_path('app/backups/' . $filename); $command = sprintf('mysqldump -u%s -p%s %s | gzip > %s', env('DB_USERNAME'), env('DB_PASSWORD'), env('DB_DATABASE'), $path); Process::run($command); return $path; } public function backupFiles(string $directory, string $zipName = 'files_backup.zip'): string { $path = storage_path('app/backups/' . $zipName); $zip = new ZipArchive(); if ($zip->open($path, ZipArchive::CREATE | ZipArchive::OVERWRITE) === true) { $files = new \RecursiveIteratorIterator(new \RecursiveDirectoryIterator($directory)); foreach ($files as $file) { if (!$file->isDir()) { $zip->addFile($file->getRealPath(), $file->getBasename()); } } $zip->close(); } return $path; } public function encryptFile(string $filePath): string { $key = env('BACKUP_ENCRYPTION_KEY'); $encryptedPath = $filePath . '.enc'; $data = file_get_contents($filePath); $encryptedData = openssl_encrypt($data, 'aes-256-cbc', $key, 0, substr(md5($key), 0, 16)); file_put_contents($encryptedPath, $encryptedData); unlink($filePath); return $encryptedPath; } public function uploadToStorage(string $filePath, string $disk = 's3'): bool { try { $content = file_get_contents($filePath); return Storage::disk($disk)->put('backups/' . basename($filePath), $content); } catch (Exception $e) { Log::error('Backup Upload Failed: ' . $e->getMessage()); return false; } } }